import{_ as t,o as a,c as d,a2 as n}from"./chunks/framework.DeNJmwJc.js";const b=JSON.parse('{"title":"Chapter 16 — Delete Commands","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/16-delete-commands.md","filePath":"chapters/16-delete-commands.md"}'),o={name:"chapters/16-delete-commands.md"};function r(s,e,l,i,c,h){return a(),d("div",null,[...e[0]||(e[0]=[n(`<h1 id="chapter-16-—-delete-commands" tabindex="-1">Chapter 16 — Delete Commands <a class="header-anchor" href="#chapter-16-—-delete-commands" aria-label="Permalink to &quot;Chapter 16 — Delete Commands&quot;">​</a></h1><blockquote><p><em>&quot;In Vim, deletion is not just removal—it&#39;s the first step to cutting, moving, and reshaping text.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Deleting is one of the most common editing actions.</p><p>In Vim, deletion is really <strong>cutting</strong>—deleted text is stored in a register and can be pasted later.</p><hr><h1 id="character-deletion" tabindex="-1">Character Deletion <a class="header-anchor" href="#character-deletion" aria-label="Permalink to &quot;Character Deletion&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>x</code></td><td>Delete character under cursor</td></tr><tr><td><code>X</code></td><td>Delete character before cursor</td></tr><tr><td><code>s</code></td><td>Delete character and enter insert mode</td></tr></tbody></table><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello</span></span>
<span class="line"><span>^</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press x:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ello</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello</span></span>
<span class="line"><span>   ^</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>Press X:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Helo</span></span></code></pre></div><hr><h1 id="word-deletion" tabindex="-1">Word Deletion <a class="header-anchor" href="#word-deletion" aria-label="Permalink to &quot;Word Deletion&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>dw</code></td><td>Delete from cursor to start of next word</td></tr><tr><td><code>daw</code></td><td>Delete <strong>a word</strong> (including trailing space)</td></tr><tr><td><code>diw</code></td><td>Delete <strong>inner word</strong> (no trailing space)</td></tr><tr><td><code>db</code></td><td>Delete backward to start of word</td></tr><tr><td><code>dW</code></td><td>Delete to next WORD</td></tr></tbody></table><h2 id="examples-1" tabindex="-1">Examples <a class="header-anchor" href="#examples-1" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello Beautiful World</span></span>
<span class="line"><span>      ^</span></span>
<span class="line"><span>      </span></span>
<span class="line"><span>Press dw:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Hello World</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello Beautiful World</span></span>
<span class="line"><span>      ^</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press daw:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>HelloWorld</span></span></code></pre></div><hr><h1 id="line-deletion" tabindex="-1">Line Deletion <a class="header-anchor" href="#line-deletion" aria-label="Permalink to &quot;Line Deletion&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>dd</code></td><td>Delete entire current line</td></tr><tr><td><code>D</code></td><td>Delete from cursor to end of line</td></tr><tr><td><code>d0</code></td><td>Delete from cursor to beginning of line</td></tr><tr><td><code>d^</code></td><td>Delete from cursor to first non-blank</td></tr><tr><td><code>d$</code></td><td>Delete from cursor to end of line</td></tr><tr><td><code>dgg</code></td><td>Delete from cursor to beginning of file</td></tr><tr><td><code>dG</code></td><td>Delete from cursor to end of file</td></tr></tbody></table><h2 id="with-counts" tabindex="-1">With Counts <a class="header-anchor" href="#with-counts" aria-label="Permalink to &quot;With Counts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>3dd</code></td><td>Delete 3 lines</td></tr><tr><td><code>d5j</code></td><td>Delete 5 lines downward</td></tr></tbody></table><hr><h1 id="block-deletion" tabindex="-1">Block Deletion <a class="header-anchor" href="#block-deletion" aria-label="Permalink to &quot;Block Deletion&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>d%</code></td><td>Delete to matching bracket</td></tr><tr><td><code>d)</code></td><td>Delete to next sentence</td></tr><tr><td><code>d}</code></td><td>Delete to next paragraph</td></tr><tr><td><code>dap</code></td><td>Delete <strong>a</strong> paragraph</td></tr></tbody></table><hr><h1 id="visual-mode-deletion" tabindex="-1">Visual Mode Deletion <a class="header-anchor" href="#visual-mode-deletion" aria-label="Permalink to &quot;Visual Mode Deletion&quot;">​</a></h1><ol><li>Select text with <code>v</code>, <code>V</code>, or <code>Ctrl+v</code>.</li><li>Press <code>d</code> to delete.</li></ol><p>This is the most intuitive way to delete for beginners.</p><hr><h1 id="deleting-and-inserting-combined" tabindex="-1">Deleting and Inserting Combined <a class="header-anchor" href="#deleting-and-inserting-combined" aria-label="Permalink to &quot;Deleting and Inserting Combined&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>s</code></td><td>Delete char, enter insert</td></tr><tr><td><code>S</code></td><td>Delete line, enter insert</td></tr><tr><td><code>C</code></td><td>Delete to end of line, enter insert</td></tr><tr><td><code>cc</code></td><td>Delete line, enter insert</td></tr></tbody></table><hr><h1 id="undoing-deletions" tabindex="-1">Undoing Deletions <a class="header-anchor" href="#undoing-deletions" aria-label="Permalink to &quot;Undoing Deletions&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>u</code></td><td>Undo</td></tr><tr><td><code>Ctrl+r</code></td><td>Redo</td></tr></tbody></table><p>All deletions can be undone.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Deletes</th></tr></thead><tbody><tr><td><code>x</code></td><td>Character under cursor</td></tr><tr><td><code>dw</code></td><td>Word (from cursor)</td></tr><tr><td><code>dd</code></td><td>Current line</td></tr><tr><td><code>D</code></td><td>To end of line</td></tr><tr><td><code>dG</code></td><td>To end of file</td></tr><tr><td><code>d}</code></td><td>To end of paragraph</td></tr><tr><td><code>d%</code></td><td>To matching bracket</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>x</code> deletes a single character; <code>X</code> deletes the character before the cursor.</li><li><code>dd</code> deletes a whole line; <code>D</code> deletes to the end of the line.</li><li>Counts work: <code>3dd</code> deletes 3 lines.</li><li>Deleted text is stored in a register and can be pasted.</li><li>Combine <code>d</code> with any motion for precise deletion.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a file and practice <code>x</code>, <code>dd</code>, <code>dw</code>, <code>D</code>.</li><li>Use <code>3dd</code> to delete three lines at once.</li><li>Delete from the cursor to the end of the file with <code>dG</code>.</li><li>Use visual mode to select and delete text.</li><li>Undo all deletions with <code>u</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./17-change-commands.html"><strong>Chapter 17 — Change Commands</strong></a></p><p>Learn how to delete text and immediately enter insert mode to replace it.</p>`,52)])])}const u=t(o,[["render",r]]);export{b as __pageData,u as default};
